   334|function resolveSendBranch(
   335|  deliveryBranch: DeliveryBranchStatus['branch'],
   336|  runtimeSource: RuntimeDebugSnapshot['source'],
   337|  httpStatus: string,
   338|): SendBranchProofRow {
   339|  if (deliveryBranch === 'not_observed') {
   340|    return { branch: null, label: 'pending', context: 'no send observed' };
   341|  }
   342|
   343|  const statusFragment = httpStatus !== 'pending' && httpStatus !== 'none' ? ` · ${httpStatus}` : '';
   344|
   345|  if (deliveryBranch === 'remote_db_insert') {
   346|    if (runtimeSource === 'remote_api' || runtimeSource === 'local_app_brain') {
   347|      return { branch: 'primary_realtime', label: 'primary_realtime', context: `assistant db insert${statusFragment}` };
   348|    }
   349|    if (runtimeSource === 'provider_fallback') {
   350|      return { branch: 'alternate_shared', label: 'alternate_shared', context: `gateway db insert${statusFragment}` };
   351|    }
   352|    return { branch: 'primary_realtime', label: 'primary_realtime', context: `db insert · source ${runtimeSource}${statusFragment}` };
   353|  }
   354|
   355|  if (deliveryBranch === 'local_fallback') {
   356|    return { branch: 'snapshot_fallback', label: 'snapshot_fallback', context: `local fallback path${statusFragment}` };
   357|  }
   358|
   359|  if (deliveryBranch === 'auth_session_failure') {
   360|    return { branch: 'local_only', label: 'local_only', context: `auth/session unavailable${statusFragment}` };
