   540|async function fetchOwnerAIProxyStatus(audit: IVXOwnerAIConfigAudit): Promise<AIProxyStatusSnapshot> {
   541|  const url = buildOwnerAIProxyStatusUrl(audit);
   542|  if (!url) {
   543|    return {
   544|      ...createInitialAIProxyStatus(),
   545|      status: 'error',
   546|      error: audit.configurationError ?? 'Owner AI proxy status URL is not configured.',
   547|    };
   548|  }
   549|
   550|  const accessToken = await getIVXAccessToken();
   551|  if (!accessToken) {
   552|    return {
   553|      ...createInitialAIProxyStatus(),
   554|      status: 'blocked',
   555|      observedAt: new Date().toISOString(),
   556|      url,
   557|      error: 'Owner session token is not hydrated yet.',
   558|    };
   559|  }
   560|
   561|  const controller = new AbortController();
   562|  const timer = setTimeout(() => {
   563|    controller.abort();
   564|  }, AI_FAST_PROXY_TIMEOUT_MS);
   565|
   566|  try {
   567|    const response = await fetch(url, {
   568|      method: 'GET',
   569|      headers: {
   570|        Accept: 'application/json',
   571|        Authorization: `Bearer ${accessToken}`,
   572|      },
   573|      signal: controller.signal,
   574|    });
   575|    const payload = await response.json().catch(() => null) as Record<string, unknown> | null;
   576|    const runtime = isRecord(payload?.runtime) ? payload.runtime : {};
   577|    const runtimeConfigured = runtime.configured === true;
   578|    const deploymentMarker = typeof payload?.deploymentMarker === 'string' ? payload.deploymentMarker : null;
   579|    const model = typeof runtime.model === 'string' ? runtime.model : null;
   580|    const gateway = typeof runtime.gateway === 'string' ? runtime.gateway : null;
   581|    const error = typeof payload?.error === 'string' ? payload.error : typeof payload?.detail === 'string' ? payload.detail : null;
   582|
   583|    if (!response.ok) {
   584|      return {
   585|        status: response.status === 401 || response.status === 403 ? 'blocked' : 'error',
   586|        observedAt: new Date().toISOString(),
   587|        url,
   588|        model,
   589|        gateway,
   590|        configured: false,
   591|        deploymentMarker,
   592|        error: error ?? `Proxy status returned HTTP ${response.status}.`,
   593|      };
   594|    }
   595|
   596|    return {
   597|      status: runtimeConfigured ? 'connected' : 'error',
   598|      observedAt: new Date().toISOString(),
   599|      url,
   600|      model,
   601|      gateway,
   602|      configured: runtimeConfigured,
   603|      deploymentMarker,
   604|      error: runtimeConfigured ? null : 'Proxy route is live, but AI gateway configuration is not ready.',
   605|    };
   606|  } catch (error) {
   607|    return {
   608|      ...createInitialAIProxyStatus(),
   609|      status: 'error',
   610|      observedAt: new Date().toISOString(),
   611|      url,
   612|      error: error instanceof Error ? error.message : 'Unable to reach Owner AI proxy status.',
   613|    };
   614|  } finally {
   615|    clearTimeout(timer);
   616|  }
